arguments.argument:
//if the character's falling
if global.gamePaused=false
{
  if falling
  {
    timeUntilFall-=1
    if timeUntilFall<=0
    {
      yAcc=grav
      if yVel>6 {yVel=6}
    }
  }
  else
  {
    if findTargetX<drawRangeX and findTargetY<drawRangeY
    {
      //if the character stands on the platform, start the timer
      if isCollisionCharacterTop(1,0)
        falling=1
    }
  }
}
